# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, request, jsonify
from pymongo import MongoClient
from bson import ObjectId
import json

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('mongodb://localhost:27017/')
db = client['content_management_system']
users_collection = db['users']
documents_collection = db['documents']

# User profile storage
@app.route('/users', methods=['POST'])
def create_user():
    user_data = request.get_json()
    user_id = users_collection.insert_one(user_data).inserted_id
    return jsonify({"user_id": str(user_id)}), 201

@app.route('/users/<user_id>', methods=['GET'])
def get_user(user_id):
    user = users_collection.find_one({"_id": ObjectId(user_id)})
    if user:
        user['_id'] = str(user['_id'])
        return jsonify(user)
    return jsonify({"error": "User not found"}), 404

@app.route('/users/<user_id>', methods=['PUT'])
def update_user(user_id):
    user_data = request.get_json()
    result = users_collection.update_one(
        {"_id": ObjectId(user_id)},
        {"$set": user_data}
    )
    if result.matched_count:
        return jsonify({"message": "User updated"})
    return jsonify({"error": "User not found"}), 404

# Document queries
@app.route('/documents', methods=['POST'])
def create_document():
    document_data = request.get_json()
    document_id = documents_collection.insert_one(document_data).inserted_id
    return jsonify({"document_id": str(document_id)}), 201

@app.route('/documents', methods=['GET'])
def get_documents():
    query = request.args.to_dict()
    documents = list(documents_collection.find(query))
    for doc in documents:
        doc['_id'] = str(doc['_id'])
    return jsonify(documents)

@app.route('/documents/<doc_id>', methods=['GET'])
def get_document(doc_id):
    document = documents_collection.find_one({"_id": ObjectId(doc_id)})
    if document:
        document['_id'] = str(document['_id'])
        return jsonify(document)
    return jsonify({"error": "Document not found"}), 404

# Aggregation pipelines
@app.route('/documents/aggregate', methods=['POST'])
def aggregate_documents():
    pipeline = request.get_json()
    try:
        result = list(documents_collection.aggregate(pipeline))
        return jsonify(result)
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route('/users/aggregate', methods=['POST'])
def aggregate_users():
    pipeline = request.get_json()
    try:
        result = list(users_collection.aggregate(pipeline))
        return jsonify(result)
    except Exception as e:
        return jsonify({"error": str(e)}), 400

if __name__ == '__main__':
    app.run(debug=True)